// ─── Collect all platform inputs ───────────────────────────────────────────
const tiktokData   = $('TikTok Trending Hashtags').first().json;
const youtubeData  = $('YouTube Trending Videos').first().json;
const instagramData = $('Instagram Trending Hashtags').first().json;

const now = new Date().toISOString();

// ─── Helper: cap score to 100 ────────────────────────────────────────────────
function clamp(val, min = 0, max = 100) {
  return Math.min(max, Math.max(min, val));
}

// ─── Normalize TikTok hashtags ───────────────────────────────────────────────
const tiktokTrends = [];
try {
  const hashtags = tiktokData?.data?.hashtag_list || tiktokData?.hashtag_list || [];
  for (const tag of hashtags.slice(0, 20)) {
    const views      = Number(tag.video_views || tag.viewCount || 0);
    const videoCount = Number(tag.video_count  || tag.videoCount || 1);
    const engRate    = videoCount > 0 ? (views / videoCount / 1_000_000) : 0;
    const score      = clamp(Math.round((views / 1_000_000) * 40 + engRate * 40 + 20));
    tiktokTrends.push({
      name:           `#${tag.title || tag.hashtag_name || 'unknown'}`,
      platform:       'TikTok',
      trendScore:     score,
      hashtags:       [tag.title || tag.hashtag_name || ''],
      exampleContent: tag.cover_url || tag.cover || '',
      createdAt:      now,
    });
  }
} catch (e) {
  console.log('TikTok parse error:', e.message);
}

// ─── Normalize YouTube videos ─────────────────────────────────────────────────
const youtubeTrends = [];
try {
  const items = youtubeData?.items || [];
  for (const item of items) {
    const views    = Number(item.statistics?.viewCount    || 0);
    const likes    = Number(item.statistics?.likeCount    || 0);
    const comments = Number(item.statistics?.commentCount || 0);
    const engRate  = views > 0 ? ((likes + comments) / views) * 100 : 0;
    const score    = clamp(Math.round((views / 1_000_000) * 40 + engRate * 40 + 15));
    const tags     = item.snippet?.tags?.slice(0, 5) || [];
    youtubeTrends.push({
      name:           item.snippet?.title || 'Unknown Video',
      platform:       'YouTube',
      trendScore:     score,
      hashtags:       tags,
      exampleContent: item.snippet?.thumbnails?.high?.url || '',
      createdAt:      now,
    });
  }
} catch (e) {
  console.log('YouTube parse error:', e.message);
}

// ─── Normalize Instagram posts ────────────────────────────────────────────────
const instagramTrends = [];
try {
  const posts = instagramData?.data?.posts || instagramData?.posts || [];
  for (const post of posts.slice(0, 20)) {
    const likes    = Number(post.like_count    || post.likes_count    || 0);
    const comments = Number(post.comment_count || post.comments_count || 0);
    const caption  = (post.caption?.text || post.caption || '').slice(0, 200);
    // extract hashtags from caption
    const tagMatches = caption.match(/#[\w]+/g) || [];
    const score = clamp(Math.round(((likes + comments) / 1000) * 40 + tagMatches.length * 2 + 10));
    instagramTrends.push({
      name:           caption.slice(0, 80) || `#trending post`,
      platform:       'Instagram',
      trendScore:     score,
      hashtags:       tagMatches.slice(0, 10),
      exampleContent: post.thumbnail_url || post.display_url || '',
      createdAt:      now,
    });
  }
} catch (e) {
  console.log('Instagram parse error:', e.message);
}

// ─── Merge & sort by trendScore desc ─────────────────────────────────────────
const allTrends = [...tiktokTrends, ...youtubeTrends, ...instagramTrends]
  .sort((a, b) => b.trendScore - a.trendScore);

// Return one item per trend so downstream nodes iterate
return allTrends.map(trend => ({ json: trend }));
